9	} from 'react-native';
10	import Animated, {
11	  useAnimatedStyle,
12	  useSharedValue,
13	  withSpring,
14	  type WithSpringConfig,
15	} from 'react-native-reanimated';
16	import * as Haptics from 'expo-haptics';
17	import { colors, radii, shadows, spacing } from '@/design/tokens';
18	import { SPRING_SOFT, withReducedMotion } from '@/design/motion';
19	import { useReducedMotion } from '@/design/useReducedMotion';
20	import { textStyles } from '@/design/typography';
21	import { StatusPill, type StatusPillStatus } from './StatusPill';
22	
23	export type CampaignCardCurrency = 'USD' | 'EUR' | 'GBP';
24	
25	export type CampaignCardProps = {
26	  title: string;
27	  listerHandle: string;
28	  priceCents: number;
29	  currency?: CampaignCardCurrency;
30	  preConditionSummary?: string;
31	  status?: StatusPillStatus;
32	  onPress?: () => void;
33	  style?: StyleProp<ViewStyle>;
34	  testID?: string;
35	};
36	
37	const CURRENCY_SYMBOL: Record<CampaignCardCurrency, string> = {
38	  USD: '$',
39	  EUR: '€',
40	  GBP: '£',
41	};
42	
43	function formatPrice(priceCents: number, currency: CampaignCardCurrency): string {
44	  const whole = Math.round(priceCents / 100);
45	  return `${CURRENCY_SYMBOL[currency]}${whole.toLocaleString('en-US')}`;
46	}
47	
48	// Feed cell per docs/design.md §5.1 — hard-shadow card, 2px ink border. Press
49	// behavior per §1.4 line 103: shadow collapses (3,3) → (0,0) while the card
50	// translates (3,3) to mimic a physical press. Same animated-shadowOpacity + fixed
51	// shadowOffset pattern as Button/Chip since iOS shadowOffset is not animatable
52	// through Reanimated.
53	export function CampaignCard({
54	  title,
55	  listerHandle,
56	  priceCents,
57	  currency = 'USD',
58	  preConditionSummary,
59	  status,
60	  onPress,
61	  style,
62	  testID,
63	}: CampaignCardProps) {
64	  const reduced = useReducedMotion();
65	  const pressed = useSharedValue(0);
66	  const interactive = !!onPress;
67	
68	  const animatedStyle = useAnimatedStyle(() => {
69	    const v = pressed.value;
70	    return {
71	      transform: [{ translateX: v * 3 }, { translateY: v * 3 }],
72	      shadowOpacity: 1 - v,
73	    };
74	  });
75	
76	  const handlePressIn = useCallback(() => {
77	    if (!interactive) return;
78	    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
79	    pressed.value = withSpring(1, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
80	  }, [interactive, pressed, reduced]);
81	
82	  const handlePressOut = useCallback(() => {
83	    if (!interactive) return;
84	    pressed.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
85	  }, [interactive, pressed, reduced]);
86	
87	  return (
88	    <Pressable
89	      onPress={interactive ? onPress : undefined}
90	      onPressIn={handlePressIn}
91	      onPressOut={handlePressOut}
92	      disabled={!interactive}
93	      accessible={interactive}
94	      accessibilityRole={interactive ? 'button' : undefined}
95	      accessibilityLabel={interactive ? `${title} by ${listerHandle}` : undefined}
96	      testID={testID}
97	    >
98	      <Animated.View style={[styles.card, shadows.hard, animatedStyle, style]}>
99	        <Text style={[textStyles.h2, styles.title]} numberOfLines={2}>
100	          {title}
101	        </Text>
102	        <Text style={[textStyles.mono, styles.handle]} numberOfLines={1}>
103	          {listerHandle}
104	        </Text>
105	        {preConditionSummary ? (
106	          <Text style={[textStyles.caption, styles.preCondition]} numberOfLines={2}>
107	            {preConditionSummary}
108	          </Text>
109	        ) : null}
110	        <View style={styles.footerRow}>
111	          <Text style={[textStyles.h2, styles.price]}>{formatPrice(priceCents, currency)}</Text>
112	          {status ? <StatusPill status={status} /> : null}
113	        </View>
114	      </Animated.View>
115	    </Pressable>
116	  );
117	}
118	
119	const styles = StyleSheet.create({
120	  card: {
121	    backgroundColor: colors.surface,
122	    borderRadius: radii.card,
123	    borderWidth: 2,
124	    borderColor: colors.ink,
125	    padding: spacing.base,
126	    gap: spacing.xs,
127	  },
128	  title: {
129	    color: colors.ink,
