1	import { useCallback, useEffect, useState } from 'react';
2	import {
3	  RefreshControl,
4	  SafeAreaView,
5	  ScrollView,
6	  StyleSheet,
7	  Text,
8	  View,
9	} from 'react-native';
10	import { router } from 'expo-router';
11	import { Fab } from '@/components/shared/Fab';
12	import { SkeletonCard } from '@/components/primitives/SkeletonCard';
13	import { colors, radii, shadows, spacing } from '@/design/tokens';
14	import { textStyles } from '@/design/typography';
15	import { useAuth } from '@/lib/auth';
16	import { supabase } from '@/lib/supabase';
17	import type { Database } from '@/types/supabase';
18	
19	// US-048 — Lister Home/dashboard. Calls `lister_dashboard_counts` (single
20	// SECURITY INVOKER RPC returning three ints: active_campaigns,
